namespace RawrXD::Training {

// Real training implementation
class ModelTrainerImpl {
public:
    struct TrainingConfig {
        // Model
        std::string base_model_path;
        std::string output_path;
        
        // Data
        std::string dataset_path;
        int max_sequence_length = 2048;
        int batch_size = 4;
        int gradient_accumulation_steps = 4;
        
        // Optimization
        float learning_rate = 5e-5f;
        float min_learning_rate = 1e-6f;
        float weight_decay = 0.01f;
        float beta1 = 0.9f;
        float beta2 = 0.999f;
        float epsilon = 1e-8f;
        float max_grad_norm = 1.0f;
        int warmup_steps = 100;
        int max_steps = 1000;
        
        // Logging
        int log_interval = 10;
        int save_interval = 100;
        std::string checkpoint_dir;
        
        // LoRA
        bool use_lora = true;
        int lora_rank = 16;
        float lora_alpha = 32.0f;
        float lora_dropout = 0.05f;
    };
    
    struct TrainingState {
        int current_step = 0;
        int current_epoch = 0;
        float current_loss = 0.0f;
        float learning_rate = 0.0f;
        float best_loss = INFINITY;
        int tokens_processed = 0;
        std::chrono::steady_clock::time_point start_time;
    };
    
    // REPLACES STUB: train
    bool train(const TrainingConfig& config,
              std::function<void(const TrainingState&)> callback = nullptr) {
        
        LOG_INFO("Starting training from model: %s", config.base_model_path.c_str());
        
        // 1. Load base model
        GGUFLoader loader;
        if (!loader.load(config.base_model_path)) {
            LOG_ERROR("Failed to load base model");
            return false;
        }
        
        ModelWeights weights = loader.get_weights();
        ModelConfig model_config = loader.get_config();
        
        // 2. Apply LoRA if enabled
        LoRAManager lora;
        if (config.use_lora) {
            if (!lora.initialize(weights, config.lora_rank, 
                               config.lora_alpha, config.lora_dropout)) {
                LOG_ERROR("Failed to initialize LoRA");
                return false;
            }
            LOG_INFO("LoRA enabled: rank=%d, alpha=%.1f", 
                    config.lora_rank, config.lora_alpha);
        }
        
        // 3. Initialize optimizer (AdamW)
        AdamWOptimizer optimizer(config.learning_rate, config.beta1, 
                                config.beta2, config.epsilon, config.weight_decay);
        
        if (config.use_lora) {
            optimizer.initialize(lora.get_trainable_params());
        } else {
            optimizer.initialize(weights.get_all_params());
        }
        
        // 4. Load dataset
        TextDataset dataset(config.dataset_path, 
                          config.max_sequence_length,
                          loader.get_tokenizer());
        
        DataLoader dataloader(dataset, config.batch_size, /*shuffle=*/true);
        
        // 5. Training loop
        TrainingState state;
        state.start_time = std::chrono::steady_clock::now();
        state.learning_rate = config.learning_rate;
        
        int accumulation_step = 0;
        
        for (state.current_step = 0; 
             state.current_step < config.max_steps; 
             state.current_step++) {
            
            // Get batch
            Batch batch = dataloader.next();
            if (batch.empty()) {
                state.current_epoch++;
                dataloader.reset();
                batch = dataloader.next();
            }
            
            // Forward pass
            std::vector<float> logits;
            std::vector<float> loss_grads;
            
            float loss = forward_backward_pass(batch, weights, lora, 
                                              logits, loss_grads);
            
            state.current_loss = loss;
            state.tokens_processed += batch.num_tokens();
            
            // Gradient accumulation
            accumulation_step++;
            if (accumulation_step < config.gradient_accumulation_steps) {
                continue;  // Accumulate more gradients
            }
            
            // Update weights
            accumulation_step = 0;
            
            // Clip gradients
            if (config.max_grad_norm > 0) {
                clip_gradients(optimizer.get_gradients(), config.max_grad_norm);
            }
            
            // Learning rate schedule (cosine with warmup)
            float progress = static_cast<float>(state.current_step) / config.max_steps;
            if (state.current_step < config.warmup_steps) {
                state.learning_rate = config.learning_rate * 
                    (static_cast<float>(state.current_step) / config.warmup_steps);
            } else {
                float cosine_decay = 0.5f * (1.0f + std::cos(3.14159f * progress));
                state.learning_rate = config.min_learning_rate + 
                    (config.learning_rate - config.min_learning_rate) * cosine_decay;
            }
            
            optimizer.set_learning_rate(state.learning_rate);
            
            // Optimizer step
            optimizer.step();
            optimizer.zero_grad();
            
            // Logging
            if (state.current_step % config.log_interval == 0) {
                auto elapsed = std::chrono::duration_cast<std::chrono::seconds>(
                    std::chrono::steady_clock::now() - state.start_time).count();
                
                float tokens_per_sec = state.tokens_processed / static_cast<float>(elapsed);
                
                LOG_INFO("Step %d/%d | Loss: %.4f | LR: %.2e | Tok/s: %.1f",
                        state.current_step, config.max_steps,
                        state.current_loss, state.learning_rate, tokens_per_sec);
                
                if (callback) callback(state);
            }
            
            // Checkpointing
            if (state.current_step % config.save_interval == 0 && 
                state.current_step > 0) {
                
                if (state.current_loss < state.best_loss) {
                    state.best_loss = state.current_loss;
                    save_checkpoint(config.checkpoint_dir, state, weights, lora);
                    LOG_INFO("Checkpoint saved at step %d (best loss: %.4f)",
                            state.current_step, state.best_loss);
                }
            }
        }
        
        // 6. Save final model
        if (config.use_lora) {
            // Merge LoRA weights into base model
            lora.merge_weights(weights);
        }
        
        GGUFWriter writer;
        writer.save(config.output_path, weights, model_config);
        
        LOG_INFO("Training complete. Model saved to: %s", config.output_path.c_str());
        return true;
    }
    
    // REPLACES STUB: fine_tune_lora
    bool fine_tune_lora(const std::string& base_model,
                       const std::string& dataset,
                       const std::string& output,
                       int rank = 16,
