    float compute_cross_entropy_loss(const std::vector<float>& logits,
                                    const std::vector<std::vector<int>>& targets) {
        float total_loss = 0.0f;
        int total_tokens = 0;
        
        // Softmax + cross-entropy
        for (size_t b = 0; b < targets.size(); b++) {
            for (size_t t = 0; t < targets[b].size(); t++) {
                int vocab_idx = targets[b][t];
                
                // Get logit for target token
                float logit = logits[(b * targets[b].size() + t) * vocab_size_ + vocab_idx];
                
                // Log softmax
                float max_logit = *std::max_element(
                    logits.begin() + (b * targets[b].size() + t) * vocab_size_,
                    logits.begin() + (b * targets[b].size() + t + 1) * vocab_size_
                );
                
                float sum_exp = 0.0f;
                for (int v = 0; v < vocab_size_; v++) {
                    sum_exp += std::exp(logits[(b * targets[b].size() + t) * vocab_size_ + v] - max_logit);
                }
                
                float log_prob = logit - max_logit - std::log(sum_exp);
                total_loss -= log_prob;
                total_tokens++;
            }
        }
        
        return total_loss / total_tokens;
    }
    
    std::vector<float> backward_pass(const std::vector<float>& logits,
                                    const std::vector<std::vector<int>>& targets,
                                    ModelWeights& weights,
                                    LoRAManager& lora) {
        // Compute gradients via backpropagation
        std::vector<float> grads(logits.size(), 0.0f);
        
        // dL/dlogit = softmax(logits) - one_hot(target)
        for (size_t b = 0; b < targets.size(); b++) {
            for (size_t t = 0; t < targets[b].size(); t++) {
                int target_idx = targets[b][t];
                
                // Compute softmax
                float max_logit = *std::max_element(
                    logits.begin() + (b * targets[b].size() + t) * vocab_size_,
                    logits.begin() + (b * targets[b].size() + t + 1) * vocab_size_
                );
                
                float sum_exp = 0.0f;
                std::vector<float> probs(vocab_size_);
                for (int v = 0; v < vocab_size_; v++) {
                    probs[v] = std::exp(logits[(b * targets[b].size() + t) * vocab_size_ + v] - max_logit);
                    sum_exp += probs[v];
                }
                
                for (int v = 0; v < vocab_size_; v++) {
                    probs[v] /= sum_exp;
                }
                
                // Gradient
                probs[target_idx] -= 1.0f;
                
                // Store gradients
                for (int v = 0; v < vocab_size_; v++) {
                    grads[(b * targets[b].size() + t) * vocab_size_ + v] = probs[v];
                }
            }
