    void clip_gradients(std::vector<float>& gradients, float max_norm) {
        float norm = 0.0f;
        for (float g : gradients) {
            norm += g * g;
        }
        norm = std::sqrt(norm);
        
        if (norm > max_norm) {
            float scale = max_norm / norm;
            for (float& g : gradients) {
                g *= scale;
            }
        }
    }
    
