void handle_std_exception(const std::exception& e, 
                         const char* context,
                         const char* file,
                         int line) {
    LOG_ERROR("[%s:%d] %s - %s: %s", 
             file, line, context, typeid(e).name(), e.what());
    
    // Attempt recovery based on exception type
    if (dynamic_cast<const std::bad_alloc*>(&e)) {
        // Memory pressure - try to free caches
        MemoryManager::emergency_cleanup();
    } else if (dynamic_cast<const std::runtime_error*>(&e)) {
        // Runtime error - may be recoverable
        Telemetry::track_exception("runtime_error", e.what(), context);
    }
}

void handle_unknown_exception(const char* context,
                             const char* file,
                             int line) {
    LOG_ERROR("[%s:%d] %s - Unknown exception", file, line, context);
    Telemetry::track_exception("unknown", "caught by ellipsis", context);
    
    // Attempt graceful shutdown
    EmergencyShutdown::initiate();
