template<typename T>
class UniqueHandle {
    T handle_;
    std::function<void(T)> deleter_;
    
public:
    UniqueHandle(T handle, std::function<void(T)> deleter) 
        : handle_(handle), deleter_(deleter) {}
    
    ~UniqueHandle() { if (handle_) deleter_(handle_); }
    
    // Move only
    UniqueHandle(UniqueHandle&& other) 
        : handle_(other.release()), deleter_(other.deleter_) {}
    UniqueHandle& operator=(UniqueHandle&& other) {
        if (this != &other) {
            reset(other.release());
            deleter_ = other.deleter_;
        }
        return *this;
    }
    
    T get() const { return handle_; }
    T release() { T tmp = handle_; handle_ = nullptr; return tmp; }
    void reset(T handle = nullptr) {
        if (handle_) deleter_(handle_);
        handle_ = handle;
    }
    
    // Delete copy
    UniqueHandle(const UniqueHandle&) = delete;
    UniqueHandle& operator=(const UniqueHandle&) = delete;
};

